import{z as a,x as t,b as e,c as o,i as p}from"./index-dc5fff9e.js";const c={class:"markdown-body"},l=p(`<p>记录了与NRF52相关的资料</p><h2>存储空间布局</h2><table><thead><tr><th>组件</th><th>存储空间范围 S132</th><th>存储空间范围 S140</th><th>存储空间范围 S112</th></tr></thead><tbody><tr><td>Bootloader settings</td><td>0x0007 F000~0x0008 0000(4KiB)</td><td>0x000F F000~0x0010 0000(4KiB)</td><td>0x0002 F000~0x0003 0000(4KiB)</td></tr><tr><td>MBR parameter storage</td><td>0x0007 E000~0x0007 F000(4Kib)</td><td>0x000F E000~0x000F F000(4Kib)</td><td>0x0002 E000~0x0002 F000(4KiB)</td></tr><tr><td>Bootloader</td><td>0x0007 8000~0x0007 E000(24KiB)</td><td>0x000F 8000~0x000F E000(24KiB)</td><td>0x0002 8000~0x0002 E000 (24KiB)</td></tr><tr><td>Application area</td><td>0x0002 6000~0x0007 8000(328KiB)</td><td>0x0002 6000~0x000F 8000(840KiB)</td><td>0x0001 9000~0x0002 8000(60KiB)</td></tr><tr><td>SoftDevice</td><td>0x0000 1000~0x0002 6000(148KiB)</td><td>0x0000 1000 - 0x0002 6000(148KiB)</td><td>0x0000 1000 - 0x0001 9000(96KiB)</td></tr><tr><td>Master Boot Record(MBR)</td><td>0x0000 0000~0x0000 1000(4KiB)</td><td>0x0000 0000~0x0000 1000(4KiB)</td><td>0x0000 0000~0x0000 1000(4KiB)</td></tr></tbody></table><br><hr><h2>Bootloader</h2><h3>参数</h3><p>bootloader 开始地址存放到 UICR.BOOTLOADERADDR 中，UICR.BOOTLOADERADDR 被映射在 0x10001014 (NRF_UICR_BOOTLOADER_START_ADDRESS)</p><h3>跳转</h3><p>bootloader 跳转到 APP 前的处理：<br> 在含有协议库的情况下</p><div class="code-wrapper"><div class="heading-row no-heading show-lang"><span class="lang-display">c</span></div><div class="code-block language-c no-line-numbers" data-lang="c" data-modifiers=""><pre class="language-c" data-lang="c"><code class="code-line odd first-row line-1"><span class="token class-name">sd_mbr_command_t</span> command <span class="token operator">=</span></code>
<code class="code-line even line-2"><span class="token punctuation">{</span></code>
<code class="code-line odd line-3">    <span class="token punctuation">.</span>command <span class="token operator">=</span> SD_MBR_COMMAND_IRQ_FORWARD_ADDRESS_SET<span class="token punctuation">,</span></code>
<code class="code-line even line-4">    <span class="token punctuation">.</span>params<span class="token punctuation">.</span>irq_forward_address_set<span class="token punctuation">.</span>address <span class="token operator">=</span> <span class="token number">0x1000</span><span class="token punctuation">,</span></code>
<code class="code-line odd line-5"><span class="token punctuation">}</span><span class="token punctuation">;</span></code>
<code class="code-line even line-6">ret_val <span class="token operator">=</span> <span class="token function">sd_mbr_command</span><span class="token punctuation">(</span><span class="token operator">&amp;</span>command<span class="token punctuation">)</span><span class="token punctuation">;</span></code>
<code class="code-line odd line-7"><span class="token keyword">if</span><span class="token punctuation">(</span>NRF_ERROR_INVALID_PARAM <span class="token operator">==</span> ret_val<span class="token punctuation">)</span><span class="token punctuation">{</span></code>
<code class="code-line even line-8">    <span class="token operator">*</span><span class="token punctuation">(</span><span class="token class-name">uint32_t</span> <span class="token operator">*</span><span class="token punctuation">)</span><span class="token punctuation">(</span><span class="token number">0x20000000</span><span class="token punctuation">)</span> <span class="token operator">=</span> <span class="token number">0x1000</span><span class="token punctuation">;</span></code>
<code class="code-line odd line-9"><span class="token punctuation">}</span></code>
<code class="code-line even line-10"><span class="token punctuation">.</span><span class="token punctuation">.</span><span class="token punctuation">.</span><span class="token punctuation">.</span><span class="token punctuation">.</span><span class="token punctuation">.</span></code>
<code class="code-line odd line-11"><span class="token keyword">const</span> <span class="token class-name">uint32_t</span> jmp_addr <span class="token operator">=</span> <span class="token operator">*</span><span class="token punctuation">(</span><span class="token punctuation">(</span><span class="token class-name">uint32_t</span> <span class="token operator">*</span><span class="token punctuation">)</span><span class="token punctuation">(</span>_addr <span class="token operator">+</span> <span class="token keyword">sizeof</span><span class="token punctuation">(</span><span class="token class-name">uint32_t</span><span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">;</span>  <span class="token comment">//_addr 为APP所在地址</span></code>
<code class="code-line even line-12"><span class="token function">__disable_irq</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span></code>
<code class="code-line odd line-13"><span class="token keyword">for</span><span class="token punctuation">(</span><span class="token class-name">uint8_t</span> i<span class="token operator">=</span><span class="token number">0</span><span class="token punctuation">;</span>i<span class="token operator">&lt;</span><span class="token number">8</span><span class="token punctuation">;</span>i<span class="token operator">++</span><span class="token punctuation">)</span></code>
<code class="code-line even line-14"><span class="token punctuation">{</span></code>
<code class="code-line odd line-15">    NVIC<span class="token operator">-&gt;</span>ICER<span class="token punctuation">[</span>i<span class="token punctuation">]</span><span class="token operator">=</span><span class="token number">0xFFFFFFFF</span><span class="token punctuation">;</span></code>
<code class="code-line even line-16">    NVIC<span class="token operator">-&gt;</span>ICPR<span class="token punctuation">[</span>i<span class="token punctuation">]</span><span class="token operator">=</span><span class="token number">0xFFFFFFFF</span><span class="token punctuation">;</span></code>
<code class="code-line odd line-17"><span class="token punctuation">}</span></code>
<code class="code-line even line-18"><span class="token function">__set_CONTROL</span><span class="token punctuation">(</span><span class="token number">0</span><span class="token punctuation">)</span><span class="token punctuation">;</span>   <span class="token comment">// Set CONTROL to its reset value 0.</span></code>
<code class="code-line odd line-19"><span class="token function">__set_PRIMASK</span><span class="token punctuation">(</span><span class="token number">0</span><span class="token punctuation">)</span><span class="token punctuation">;</span>   <span class="token comment">// Set PRIMASK to its reset value 0.</span></code>
<code class="code-line even line-20"><span class="token function">__set_BASEPRI</span><span class="token punctuation">(</span><span class="token number">0</span><span class="token punctuation">)</span><span class="token punctuation">;</span>   <span class="token comment">// Set BASEPRI to its reset value 0.</span></code>
<code class="code-line odd line-21"><span class="token function">__set_FAULTMASK</span><span class="token punctuation">(</span><span class="token number">0</span><span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// Set FAULTMASK to its reset value 0.</span></code>
<code class="code-line even line-22"><span class="token function">__enable_irq</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span></code>
<code class="code-line odd last-row line-23"><span class="token punctuation">(</span><span class="token punctuation">(</span><span class="token keyword">void</span> <span class="token punctuation">(</span><span class="token operator">*</span><span class="token punctuation">)</span><span class="token punctuation">(</span><span class="token keyword">void</span><span class="token punctuation">)</span><span class="token punctuation">)</span>jmp_addr<span class="token punctuation">)</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span></code></pre></div></div><p>需要注意的是：<br> 1.中断向表是在0x00000000的位置，并不是在APP所在地址的位置。<br> 2.使用__set_MSP，会使程序跑飞。<br> 3.当 SD_EVT_IRQHandler 无响应时，需要包含头文件“nrf_soc.h”，或使用 SWI2_EGU2_IRQHandler。</p><br><hr><h2>DFU 参数</h2><p>关于结构体nrf_dfu_settings_t的内部成员描述。</p><table><thead><tr><th>类型</th><th>说明</th></tr></thead><tbody><tr><td>crc</td><td>存储的DFU设置的CRC，不包括CRC本身。如果0xFFFFFFF，表示CRC从未计算过。</td></tr><tr><td>boot_validation_app.bytes</td><td>存储新固件的CRC32数据</td></tr><tr><td>progress.update_start_address</td><td>bank1在flash的起始地址</td></tr><tr><td>bank1.image_size</td><td>新固件大小</td></tr><tr><td>bank1.image_crc</td><td>新固件的CRC校验值，可以用crc32_compute()计算</td></tr><tr><td>bank1.bank_code</td><td>设置为NRF_DFU_BANK_VALID_APP，使其为有效固件</td></tr></tbody></table><br><hr><h2>协议栈版本</h2><ul><li>名称格式：S[xyz] <ul><li>[ x ] 协议栈的类型，1为BLE协议栈，2为ANT协议栈，3为同时支持两者</li><li>[ y ] BLE角色，1为从设备，2为主设备，3为同时支持两者</li><li>[ z ] 芯片类型，0 为nRF51系列，2 为nRF52系列</li></ul></li></ul><br><hr><h2>BLE 提速</h2><ul><li>增大ATT_MTU为247</li><li>启动CLE功能，配置在协议栈初始化后</li></ul><div class="code-wrapper"><div class="heading-row no-heading show-lang"><span class="lang-display">c</span></div><div class="code-block language-c no-line-numbers" data-lang="c" data-modifiers=""><pre class="language-c" data-lang="c"><code class="code-line odd first-row line-1"><span class="token class-name">ret_code_t</span> ret <span class="token operator">=</span> NRF_SUCCESS<span class="token punctuation">;</span></code>
<code class="code-line even line-2"><span class="token class-name">ble_opt_t</span> opt <span class="token operator">=</span> <span class="token punctuation">{</span></code>
<code class="code-line odd line-3">    <span class="token punctuation">.</span>common_opt<span class="token punctuation">.</span>conn_evt_ext<span class="token punctuation">.</span>enable <span class="token operator">=</span> <span class="token number">1</span><span class="token punctuation">,</span></code>
<code class="code-line even line-4"><span class="token punctuation">}</span><span class="token punctuation">;</span></code>
<code class="code-line odd last-row line-5">ret_code <span class="token operator">=</span> <span class="token function">sd_ble_opt_set</span><span class="token punctuation">(</span>BLE_COMMON_OPT_CONN_EVT_EXT<span class="token punctuation">,</span><span class="token operator">&amp;</span>opt<span class="token punctuation">)</span><span class="token punctuation">;</span></code></pre></div></div><ul><li>增加连接事件长度：BLE_CONN_CFG_GAP</li></ul><div class="code-wrapper"><div class="heading-row no-heading show-lang"><span class="lang-display">c</span></div><div class="code-block language-c no-line-numbers" data-lang="c" data-modifiers=""><pre class="language-c" data-lang="c"><code class="code-line odd first-row line-1"><span class="token class-name">ble_cfg_t</span> cfg <span class="token operator">=</span> <span class="token punctuation">{</span></code>
<code class="code-line even line-2">    <span class="token punctuation">.</span>conn_cfg<span class="token punctuation">.</span>params<span class="token punctuation">.</span>gap_conn_cfg<span class="token punctuation">.</span>event_length <span class="token operator">=</span> <span class="token number">400</span><span class="token punctuation">,</span> <span class="token comment">/* 400*1.25ms */</span></code>
<code class="code-line odd last-row line-3"><span class="token punctuation">}</span><span class="token punctuation">;</span></code></pre></div></div><ul><li>使用BLE_GAP_PHY_2MBPS</li></ul><div class="code-wrapper"><div class="heading-row no-heading show-lang"><span class="lang-display">c</span></div><div class="code-block language-c no-line-numbers" data-lang="c" data-modifiers=""><pre class="language-c" data-lang="c"><code class="code-line odd first-row line-1"><span class="token class-name">ble_gap_phys_t</span> phy <span class="token operator">=</span> <span class="token punctuation">{</span></code>
<code class="code-line even line-2">    <span class="token punctuation">.</span>tx_phys <span class="token operator">=</span> BLE_GAP_PHY_2MBPS<span class="token punctuation">,</span></code>
<code class="code-line odd line-3">    <span class="token punctuation">.</span>rx_phys <span class="token operator">=</span> BLE_GAP_PHY_2MBPS<span class="token punctuation">,</span></code>
<code class="code-line even line-4"><span class="token punctuation">}</span><span class="token punctuation">;</span></code>
<code class="code-line odd line-5"><span class="token keyword">void</span> <span class="token function">ble_evt_handler</span><span class="token punctuation">(</span>ble_evt <span class="token keyword">const</span><span class="token operator">*</span> _event<span class="token punctuation">,</span><span class="token keyword">void</span> <span class="token operator">*</span>_context<span class="token punctuation">)</span></code>
<code class="code-line even line-6"><span class="token punctuation">{</span></code>
<code class="code-line odd line-7">    <span class="token keyword">switch</span><span class="token punctuation">(</span>_event<span class="token operator">-&gt;</span>header<span class="token punctuation">.</span>evt_id<span class="token punctuation">)</span><span class="token punctuation">{</span></code>
<code class="code-line even line-8">        <span class="token keyword">case</span> BLE_GAP_EVT_CONNECTED<span class="token operator">:</span><span class="token punctuation">{</span></code>
<code class="code-line odd line-9">            <span class="token function">sd_ble_gap_phy_update</span><span class="token punctuation">(</span>_event<span class="token operator">-&gt;</span>evt<span class="token punctuation">.</span>gap_evt<span class="token punctuation">.</span>conn_handle<span class="token punctuation">,</span><span class="token operator">&amp;</span>phy<span class="token punctuation">)</span><span class="token punctuation">;</span></code>
<code class="code-line even line-10">        <span class="token punctuation">}</span><span class="token keyword">break</span><span class="token punctuation">;</span></code>
<code class="code-line odd line-11">        <span class="token keyword">default</span> <span class="token operator">:</span><span class="token keyword">break</span><span class="token punctuation">;</span></code>
<code class="code-line even line-12">    <span class="token punctuation">}</span></code>
<code class="code-line odd last-row line-13"><span class="token punctuation">}</span></code></pre></div></div><ul><li>调整连接间隔，其中BLE_CONN_CFG_GAP大于等于maxval。 <ul><li>50ms - 1328kbps</li><li>400ms - 1376kbps</li></ul></li></ul><div class="code-wrapper"><div class="heading-row no-heading show-lang"><span class="lang-display">c</span></div><div class="code-block language-c no-line-numbers" data-lang="c" data-modifiers=""><pre class="language-c" data-lang="c"><code class="code-line odd first-row line-1"><span class="token class-name">ble_gap_conn_params_t</span> params <span class="token operator">=</span> <span class="token punctuation">{</span></code>
<code class="code-line even line-2">    <span class="token punctuation">.</span>min_conn_interval <span class="token operator">=</span> minval<span class="token punctuation">,</span>  <span class="token comment">/*最小连接间隔 单位：1.25ms*/</span></code>
<code class="code-line odd line-3">    <span class="token punctuation">.</span>max_conn_interval <span class="token operator">=</span> maxval<span class="token punctuation">,</span>  <span class="token comment">/*最大连接间隔 单位：1.25ms*/</span></code>
<code class="code-line even last-row line-4"><span class="token punctuation">}</span><span class="token punctuation">;</span></code></pre></div></div><ul><li>增大协议栈发送Buff</li></ul><div class="code-wrapper"><div class="heading-row no-heading show-lang"><span class="lang-display">c</span></div><div class="code-block language-c no-line-numbers" data-lang="c" data-modifiers=""><pre class="language-c" data-lang="c"><code class="code-line odd first-row line-1"><span class="token class-name">ret_code_t</span> ret <span class="token operator">=</span> NRF_SUCCESS<span class="token punctuation">;</span></code>
<code class="code-line even line-2"><span class="token class-name">ble_cfg_t</span> cfg <span class="token operator">=</span> <span class="token punctuation">{</span></code>
<code class="code-line odd line-3">    <span class="token punctuation">.</span>conn_cfg<span class="token punctuation">.</span>conn_cfg_tag <span class="token operator">=</span> CFG_Tag<span class="token punctuation">,</span></code>
<code class="code-line even line-4">    <span class="token punctuation">.</span>conn_cfg<span class="token punctuation">.</span>params<span class="token punctuation">.</span>gattc_conn_cfg<span class="token punctuation">.</span>write_cmd_tx_queue_size <span class="token operator">=</span> <span class="token number">10</span><span class="token punctuation">,</span></code>
<code class="code-line odd line-5">    <span class="token punctuation">.</span>conn_cfg<span class="token punctuation">.</span>params<span class="token punctuation">.</span>gatts_conn_cfg<span class="token punctuation">.</span>hvn_tx_queue_size <span class="token operator">=</span> <span class="token number">10</span></code>
<code class="code-line even line-6"><span class="token punctuation">}</span><span class="token punctuation">;</span></code>
<code class="code-line odd last-row line-7">ret <span class="token operator">=</span> <span class="token function">sd_ble_cfg_set</span><span class="token punctuation">(</span>BLE_CONN_CFG_GATTC<span class="token punctuation">,</span><span class="token operator">&amp;</span>cfg<span class="token punctuation">,</span>rm_start<span class="token punctuation">)</span><span class="token punctuation">;</span></code></pre></div></div><h2>API接口</h2><p>中断：SD_EVT_IQHandler -&gt; SWI2_EGU2_IRQHandler</p><p>sd_ble_evt_get(uint8_t *p_dest, uint16_t *p_len) 该函数用于获取蓝牙事件。一共分为五类</p><ul><li>L2CAP</li><li>GATTS</li><li>GATTC</li><li>GAP</li><li>BASE</li></ul><p>其中，GATTS分为</p><ul><li>WRITE,调用 TEX_BLE_Event_GATTS_OPS 处理 <ul><li>BLE_GATTS_OP_INVALID</li><li>BLE_GATTS_OP_WRITE_REQ</li><li>BLE_GATTS_OP_WRITE_CMD <ul><li>0x2902,则为Notify开启或关闭</li></ul></li><li>BLE_GATTS_OP_SIGN_WRITE_CMD</li><li>BLE_GATTS_OP_PREP_WRITE_REQ</li><li>BLE_GATTS_OP_EXEC_WRITE_REQ_CANCEL</li><li>BLE_GATTS_OP_EXEC_WRITE_REQ_NOW</li></ul></li><li>RW_AUTHORIZE_REQUEST，调用 Tex_BLE_Event_GATTS_RAROPS 处理，处理数据状态，大小等。</li><li>SYS_ATTR_MISSING</li><li>HVC</li><li>SC_CONFIRM</li><li>EXCHAGE_MTU_REQUEST，调用 sd_ble_gatts_exchange_mtu_reply 处理。</li><li>TIMEOUT</li><li>HVN_TX_COMPLETE</li></ul><p>GATTC分为</p><ul><li>BLE_GATTC_EVT_PRIM_SRVC_DISC_RSP</li><li>BLE_GATTC_EVT_REL_DISC_RSP</li><li>BLE_GATTC_EVT_CHAR_DISC_RSP</li><li>BLE_GATTC_EVT_DESC_DISC_RSP</li><li>BLE_GATTC_EVT_ATTR_INFO_DISC_RSP</li><li>BLE_GATTC_EVT_CHAR_VAL_BY_UUID_READ_RSP</li><li>BLE_GATTC_EVT_READ_RSP</li><li>BLE_GATTC_EVT_CHAR_VALS_READ_RSP</li><li>BLE_GATTC_EVT_WRITE_RSP</li><li>BLE_GATTC_EVT_HVX</li><li>BLE_GATTC_EVT_EXCHANGE_MTU_RSP</li><li>BLE_GATTC_EVT_TIMEOUT</li><li>BLE_GATTC_EVT_WRITE_CMD_TX_COMPLETE</li></ul><p>其中GAP分为</p><ul><li>BLE_GAP_EVT_CONNECTED 获得设备的MAC和连接参数</li><li>BLE_GAP_EVT_DISCONNECTED 获得断开连接的原因</li><li>BLE_GAP_EVT_CONN_PARAM_UPDATE</li><li>BLE_GAP_EVT_SEC_PARAMS_REQUEST</li><li>BLE_GAP_EVT_SEC_INFO_REQUEST</li><li>BLE_GAP_EVT_PASSKEY_DISPLAY</li><li>BLE_GAP_EVT_KEY_PRESSED</li><li>BLE_GAP_EVT_AUTH_KEY_REQUEST</li><li>BLE_GAP_EVT_LESC_DHKEY_REQUEST</li><li>BLE_GAP_EVT_AUTH_STATUS</li><li>BLE_GAP_EVT_CONN_SEC_UPDATE</li><li>BLE_GAP_EVT_TIMEOUT</li><li>BLE_GAP_EVT_RSSI_CHANGED</li><li>BLE_GAP_EVT_ADV_REPORT</li><li>BLE_GAP_EVT_SEC_REQUEST</li><li>BLE_GAP_EVT_CONN_PARAM_UPDATE_REQUEST</li><li>BLE_GAP_EVT_SCAN_REQ_REPORT</li><li>BLE_GAP_EVT_PHY_UPDATE_REQUEST</li><li>BLE_GAP_EVT_PHY_UPDATE</li><li>BLE_GAP_EVT_DATA_LENGTH_UPDATE_REQUEST</li><li>BLE_GAP_EVT_DATA_LENGTH_UPDATE</li><li>BLE_GAP_EVT_QOS_CHANNEL_SURVEY_REPORT</li><li>BLE_GAP_EVT_ADV_SET_TERMINATED</li></ul><h2>流程</h2><p>Softdevice启动</p><ul><li>sd_softdevice_enable</li><li>sd_nvic_EnableIRQ</li></ul><p>Stack Init</p><ul><li>配置连接参数，如连接数量，MTU大小</li><li>GATTS attribute表格</li><li>sd_ble_enable</li></ul><p>GAP参数配置</p><ul><li>sd_ble_gap_device_name_set 配置设备名字</li><li>sd_ble_gap_ppcp_set 配置连接间隔</li></ul><p>初始化广播数据</p><ul><li>主动广播</li><li>被动广播</li></ul><p>添加BLE服务和特征值</p><ul><li>配置UUiD</li><li>配置Characteristic属性：Notify,Read,Write,Indicate</li></ul>`,55),i=[l],k={layout:"post",title:"NRF52 资料",series:"techs",modtime:"2023/07/18"},E="",T=a({__name:"blog",setup(d,{expose:s}){s({frontmatter:{layout:"post",title:"NRF52 资料",series:"techs",modtime:"2023/07/18"},excerpt:void 0});const n=t();return n.currentRoute.value.meta={...n.currentRoute.value.meta,layout:"post"},(_,u)=>(e(),o("div",c,i))}});export{T as default,E as excerpt,k as frontmatter};
